def validate_cta_count(page_content: str) -> dict:
    """Check for single CTA consistency"""
    import re

    # Common CTA patterns
    cta_patterns = [
        r"buy now", r"get started", r"sign up", r"download", 
        r"book a call", r"schedule", r"register", r"enroll",
        r"get access", r"start now", r"join", r"subscribe"
    ]

    found_ctas = {}
    content_lower = page_content.lower()

    for pattern in cta_patterns:
        matches = re.findall(pattern, content_lower)
        if matches:
            found_ctas[pattern] = len(matches)

    unique_ctas = len(found_ctas)
    issues = []

    if unique_ctas > 2:
        issues.append(f"Multiple CTA types found ({unique_ctas}): {list(found_ctas.keys())}")

    return {
        "passed": unique_ctas <= 2,
        "unique_cta_count": unique_ctas,
        "ctas_found": found_ctas,
        "issues": issues
    }

def validate_proof_map(claims: list, evidence_pack: dict) -> dict:
    """Validate claims are grounded in evidence"""
    issues = []
    grounded = 0
    needs_proof = []

    for claim in claims:
        claim_text = claim.get("text", "")
        evidence_ref = claim.get("evidence_ref", None)

        if evidence_ref and evidence_ref in evidence_pack:
            grounded += 1
        else:
            needs_proof.append(claim_text[:50] + "...")
            issues.append(f"Ungrounded: '{claim_text[:30]}...'")

    return {
        "passed": len(issues) == 0,
        "grounded_count": grounded,
        "total_claims": len(claims),
        "needs_proof": needs_proof,
        "issues": issues
    }

def validate_mobile_scannability(content: str) -> dict: """Check for mobile-friendly formatting""" import re
issues = []
# Check paragraph length paragraphs = content.split("\n\n") long_paragraphs = []
for i, para in enumerate(paragraphs): sentences = len(re.findall(r'[.!?]+', para)) if sentences > 4: long_paragraphs.append(f"Paragraph {i+1}: {sentences} sentences")
if long_paragraphs: issues.append(f"Long paragraphs (>4 sentences): {len(long_paragraphs)}")
# Check subhead frequency (should be every ~150 words) words = len(content.split()) subheads = len(re.findall(r'^#{1,3}\s', content, re.MULTILINE))
expected_subheads = words // 150 if subheads < expected_subheads * 0.7: issues.append(f"Too few subheads: {subheads} found, ~{expected_subheads} expected")
return { "passed": len(issues) == 0, "word_count": words, "subhead_count": subheads, "long_paragraphs": len(long_paragraphs), "issues": issues }
